#include <iostream>
using namespace std;

class Rectangle {
private:
    int width, height;
public:
    Rectangle(int w, int h) : width(w), height(h) {
        cout << "Constructor called" << endl;
    }
    ~Rectangle() {
        cout << "Destructor called" << endl;
    }
    int area() { return width * height; }
};

int main() {
    // Dynamic allocation of single object
    Rectangle* ptr = new Rectangle(5, 10);

    cout << "Area: " << ptr->area() << endl;

    // Deallocate memory
    delete ptr;
    ptr = nullptr; // Avoid dangling pointer

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int size;
    cout << "Enter array size: ";
    cin >> size;

    // Dynamic array allocation
    int* arr = new int[size];

    // Initialize array
    for (int i = 0; i < size; i++) {
        arr[i] = i * 10;
    }

    // Display array
    cout << "Array elements: ";
    for (int i = 0; i < size; i++) {
        cout << arr[i] << " ";
    }
    cout << endl;

    // CRITICAL: Use delete[] for arrays
    delete[] arr;
    arr = nullptr;

    return 0;
}

#include <iostream>
#include <memory>
using namespace std;

class Resource {
public:
    Resource() { cout << "Resource acquired" << endl; }
    ~Resource() { cout << "Resource released" << endl; }
    void display() { cout << "Using resource" << endl; }
};

int main() {
    // unique_ptr - exclusive ownership
    cout << "--- unique_ptr ---" << endl;
    {
        unique_ptr<Resource> ptr1 = make_unique<Resource>();
        ptr1->display();
        // Automatic deallocation when ptr1 goes out of scope
    }

    // shared_ptr - shared ownership
    cout << "\n--- shared_ptr ---" << endl;
    {
        shared_ptr<Resource> ptr2 = make_shared<Resource>();
        cout << "Use count: " << ptr2.use_count() << endl;

        shared_ptr<Resource> ptr3 = ptr2; // Shared ownership
        cout << "Use count after copy: " << ptr2.use_count() << endl;

        // Automatic deallocation when last shared_ptr is destroyed
    }

    cout << "Program ending - no memory leaks!" << endl;
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int rows = 3, cols = 4;

    // Step 1: Allocate array of pointers (rows)
    int** matrix = new int*[rows];

    // Step 2: Allocate array for each row (columns)
    for (int i = 0; i < rows; i++) {
        matrix[i] = new int[cols];
    }

    // Initialize matrix
    int value = 1;
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            matrix[i][j] = value++;
        }
    }

    // Display matrix
    cout << "Matrix:" << endl;
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            cout << matrix[i][j] << "\t";
        }
        cout << endl;
    }

    // Step 3: Free each row first (IMPORTANT: reverse order)
    for (int i = 0; i < rows; i++) {
        delete[] matrix[i];
    }

    // Step 4: Free array of pointers
    delete[] matrix;
    matrix = nullptr;

    cout << "Memory properly freed!" << endl;
    return 0;
}
